/// <summary>
/// create vendor invoice journal for brokerages charges
/// </summary>
public final class ETGVendInvoiceJournalCreate
{
}

Method.Source:
public static void createVendInvJournal(VendInvoiceJour vendInvoiceJour)
{
    MCRLedgerJournal                    journalTable;
    LedgerJournalTable                  ledgerJournalTable,ledgerJournalTableUpd;
    LedgerJournalTrans                  ledgerJournalTransupd;
    ETGACFParameters                    acfParameters;
    AmountMST                           amountcredit;
    LedgerDimensionAccount              ledgerAccount,offsetAccount;
    ETG_PurchaseAgreementHeader         purchaseAgreementHeader;
    VendInvoiceTrans                    vendInvoiceTrans;

    select firstonly acfParameters;

    if(acfParameters.EnableBrokeragesMainAccount == "")
    {
        warning("@ETG_New:MainAccountBrokPurchError");
        return;
    }
    if(acfParameters.EnableBrokeragesJournalName == "")
    {
        warning("@ETG_New:JournalNameBrokPurchError");
        return;
    }

    purchaseAgreementHeader = ETGVendInvoiceJournalCreate::getBrokerageRecordPurch(vendInvoiceJour);

    if(!purchaseAgreementHeader 
        || purchaseAgreementHeader.BrokerageCommissionValue == 0 
        || purchaseAgreementHeader.Through == "")
    {
        return;
    }

    if(purchaseAgreementHeader.BrokerageCommissionType == ETGBrokerageCommissionType::Percent || purchaseAgreementHeader.BrokerageCommissionType == ETGBrokerageCommissionType::Quantity)
    {
        ttsbegin;

        journalTable       = new MCRLedgerJournal_VendInvoiceRegister(LedgerJournalType::VendInvoiceRegister, acfParameters.EnableBrokeragesJournalName);
        ledgerJournalTable = journalTable.createLedgerJournalTable(acfParameters.EnableBrokeragesJournalName);

        ledgerJournalTable.DefaultDimension = vendInvoiceJour.DefaultDimension;
        journalTable.parmLedgerJournalTable(ledgerJournalTable);
        journalTable.parmMCRCCGeneralLedgerId();
        journalTable.parmLedgerAccountType(LedgerJournalACType::Vend);
        journalTable.parmLedgerOffsetAccountType(LedgerJournalACType::Ledger);
        journalTable.parmCurrencyCode(vendInvoiceJour.CurrencyCode);
        journalTable.parmLineNum();
        ledgerJournalTable.Approver = HcmWorkerLookup::currentWorker();
        ledgerAccount               = LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber(purchaseAgreementHeader.Through, LedgerJournalACType::Vend);

        RecId ledgerDimension = LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber(acfParameters.EnableBrokeragesMainAccount,
        LedgerJournalACType::Ledger);
        offsetAccount = LedgerDimensionFacade::serviceCreateLedgerDimension(ledgerDimension, vendInvoiceJour.DefaultDimension);

        journalTable.parmLedgerAccount(ledgerAccount);
        journalTable.parmledgerOffsetAccount(offsetAccount);
        journalTable.parmTransTxt(strFmt("@ETG_New:BrokeragesJournalCreationMsg", vendInvoiceJour.InvoiceId));
        journalTable.parmInvoice(vendInvoiceJour.InvoiceId);

        if(purchaseAgreementHeader.BrokerageCommissionType == ETGBrokerageCommissionType::Percent)
        {
            amountcredit = (vendInvoiceJour.InvoiceAmount * purchaseAgreementHeader.BrokerageCommissionValue) / 100;
        }
        else
        {
            select sum(Qty) from vendInvoiceTrans
        where vendInvoiceTrans.InvoiceId == vendInvoiceJour.InvoiceId
        && vendInvoiceTrans.DataAreaId == vendInvoiceJour.DataAreaId;

            amountcredit = vendInvoiceTrans.Qty * purchaseAgreementHeader.BrokerageCommissionValue;
        }
        journalTable.parmTransDate(vendInvoiceJour.InvoiceDate);
        journalTable.parmDocumentDate(vendInvoiceJour.InvoiceDate);
        journalTable.createLedgerJournalTrans(abs(amountcredit), abs(0), LedgerJournalACType::Ledger);

        ttscommit;

        if(acfParameters.EnableBrokeragesJournalAutoPost == NoYes::Yes)
        {
            journalTable.post(ledgerJournalTable);
        }

        Info(strFmt("@ETG_New:VendorInvoiceJournalCreated", ledgerJournalTable.JournalNum));
    }

}

public static ETG_PurchaseAgreementHeader getBrokerageRecordPurch(vendInvoiceJour vendInvoiceJourETG)
{
    ETG_PurchaseAgreementHeader etgPurchAgreementHeader;
    PurchAgreementHeader     purchAgreementHeader;
    VendInvoiceTrans         vendInvoiceTrans;
    Amount brokeargeAmt;
    PurchLine  purchLine;
    AgreementLine agreementLine;

    select firstonly vendInvoiceTrans 
        where vendInvoiceTrans.InvoiceId == vendInvoiceJourETG.InvoiceId
        && vendInvoiceTrans.DataAreaId == vendInvoiceJourETG.DataAreaId;

    purchLine = vendInvoiceTrans.purchLine();

    if(purchLine && purchLine.MatchingAgreementLine)
    {
        select firstonly Agreement from agreementLine
        where agreementLine.RecId == purchLine.MatchingAgreementLine;

        select firstonly PurchNumberSequence from purchAgreementHeader
        where purchAgreementHeader.RecId == agreementLine.Agreement;

        select firstonly etgPurchAgreementHeader
        where etgPurchAgreementHeader.PurchAgreementId == purchAgreementHeader.PurchNumberSequence;
    }

    return etgPurchAgreementHeader;

}

public static ETG_SalesAgreementHeader getBrokerageRecordSales(CustInvoiceJour custInvoiceJourETG)
{
    ETG_SalesAgreementHeader etgSalesAgreementHeader;
    SalesAgreementHeader     salesAgreementHeader;
    CustInvoiceTrans         custInvoiceTrans;
    SalesLine                salesLine;
    AgreementLine            agreementLine;

    select firstonly custInvoiceTrans
        where custInvoiceTrans.InvoiceId == custInvoiceJourETG.InvoiceId
        && custInvoiceTrans.DataAreaId == custInvoiceJourETG.DataAreaId;

    salesLine = custInvoiceTrans.salesLine();

    if(salesLine && salesLine.MatchingAgreementLine)
    {
        select firstonly Agreement from agreementLine
        where agreementLine.RecId == salesLine.MatchingAgreementLine;

        select firstonly SalesNumberSequence from salesAgreementHeader
        where salesAgreementHeader.RecId == agreementLine.Agreement;

        select firstonly etgSalesAgreementHeader
        where etgSalesAgreementHeader.SalesAgreementId == salesAgreementHeader.SalesNumberSequence;
    }

    return etgSalesAgreementHeader;

}

public static void createCustInvJournal(CustInvoiceJour custInvoiceJour)
{
    MCRLedgerJournal                    journalTable;
    LedgerJournalTable                  ledgerJournalTable,ledgerJournalTableUpd;
    LedgerJournalTrans                  ledgerJournalTransupd;
    ETGACFParameters                    acfParameters;
    AmountMST                           amount;
    LedgerDimensionAccount              ledgerAccount,offsetAccount;
    ETG_SalesAgreementHeader            salesAgreementHeader;
    CustInvoiceTrans                    custInvoiceTrans;

    select firstonly acfParameters;

    if(acfParameters.EnableBrokeragesMainAccountSales == "")
    {
        warning("@ETG_New:MainAccountBrokPurchError");
        return;
    }
    if(acfParameters.EnableBrokeragesJournalName == "")
    {
        warning("@ETG_New:JournalNameBrokPurchError");
        return;
    }

    salesAgreementHeader = ETGVendInvoiceJournalCreate::getBrokerageRecordSales(custInvoiceJour);

    if(!salesAgreementHeader || salesAgreementHeader.BrokerageCommissionValue == 0 || salesAgreementHeader.Through == "")
    {
        return;
    }

    if(salesAgreementHeader.BrokerageCommissionType == ETGBrokerageCommissionType::Percent || salesAgreementHeader.BrokerageCommissionType == ETGBrokerageCommissionType::Quantity)
    {
        ttsbegin;

        journalTable       = new MCRLedgerJournal_VendInvoiceRegister(LedgerJournalType::VendInvoiceRegister, acfParameters.EnableBrokeragesJournalName);
        ledgerJournalTable = journalTable.createLedgerJournalTable(acfParameters.EnableBrokeragesJournalName);
        ledgerJournalTable.DefaultDimension = custInvoiceJour.DefaultDimension;
        journalTable.parmLedgerJournalTable(ledgerJournalTable);
        journalTable.parmMCRCCGeneralLedgerId();
        journalTable.parmLedgerAccountType(LedgerJournalACType::Vend);
        journalTable.parmLedgerOffsetAccountType(LedgerJournalACType::Ledger);
        journalTable.parmCurrencyCode(custInvoiceJour.CurrencyCode);
        journalTable.parmLineNum();
        ledgerJournalTable.Approver = HcmWorkerLookup::currentWorker();


        ledgerAccount = LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber(salesAgreementHeader.Through, LedgerJournalACType::Vend);
        RecId ledgerDimension = LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber(acfParameters.EnableBrokeragesMainAccountSales,
        LedgerJournalACType::Ledger);
        offsetAccount = LedgerDimensionFacade::serviceCreateLedgerDimension(ledgerDimension, custInvoiceJour.DefaultDimension);

        journalTable.parmLedgerAccount(ledgerAccount);
        journalTable.parmledgerOffsetAccount(offsetAccount);
        journalTable.parmTransTxt(strFmt("@ETG_New:BrokeragesJournalCreationMsg", custInvoiceJour.InvoiceId));
        journalTable.parmInvoice(custInvoiceJour.InvoiceId);

        if(salesAgreementHeader.BrokerageCommissionType == ETGBrokerageCommissionType::Percent)
        {
            amount = (custInvoiceJour.InvoiceAmount * salesAgreementHeader.BrokerageCommissionValue) / 100;
        }
        else
        {
            select sum(Qty) from custInvoiceTrans
        where custInvoiceTrans.InvoiceId == custInvoiceJour.InvoiceId
        && custInvoiceTrans.DataAreaId == custInvoiceJour.DataAreaId;

            amount = custInvoiceTrans.Qty * salesAgreementHeader.BrokerageCommissionValue;
        }
        journalTable.parmTransDate(custInvoiceJour.InvoiceDate);
        journalTable.parmDocumentDate(custInvoiceJour.InvoiceDate);
        //CS Rajat Dubey 13/05/25
        if(amount>0)
        {
            journalTable.createLedgerJournalTrans(abs(amount), abs(0), LedgerJournalACType::Ledger);
            //journalTable.createLedgerJournalTrans(abs(0), abs(amount), LedgerJournalACType::Ledger);
        }
        else
        {
            journalTable.createLedgerJournalTrans(abs(0), abs(amount), LedgerJournalACType::Ledger);
           // journalTable.createLedgerJournalTrans(abs(amount), abs(0), LedgerJournalACType::Ledger);
        }
        //CE Rajat Dubey 13/05/25
        ttscommit;

        if(acfParameters.EnableBrokeragesJournalAutoPost == NoYes::Yes)
        {
            journalTable.post(ledgerJournalTable);
        }


        Info(strFmt("@ETG_New:VendorInvoiceJournalCreated", ledgerJournalTable.JournalNum));
    }

}

